describe("structuredClone",()=>{it("Clones a simple object",()=>{let t={foo:"bar",num:42},e=structuredClone(t);expect(e).toStrictEqual(t),t.foo+="extra",expect(e).not.toStrictEqual(t)}),it("Clones an array",()=>{let t=[1,2,3,4,5],e=structuredClone(t);expect(e).toStrictEqual(t)}),it("Clones an array of objects",()=>{let t={foo:"bar"},e=[t,t,t,t,t],o=structuredClone(e);expect(o).toStrictEqual(e),expect(o[0]).not.toBe(e[0])}),it("Clones nested objects",()=>{let t={foo:{bar:{baz:"qux"}}},e=structuredClone(t);expect(e).toStrictEqual(t)}),it("Handles circular references",()=>{let t={foo:{bar:"baz",arr:[1,2,3]}};t.foo.circularRef=t,t.foo.circularRef2=t,t.foo.circularRef3=t.foo,t.ref2=t;let e=structuredClone(t);expect(e).toStrictEqual(t)}),it("Clones a Map",()=>{let t=new Map([["key1","value1"],["key2","value2"]]),e=structuredClone(t);expect(e).toStrictEqual(t)}),it("Clones a Set",()=>{let t=new Set([1,2,3,4,5]),e=structuredClone(t);expect(e).toStrictEqual(t)}),it("Clones a Date object",()=>{let t=new Date("2022-01-31T12:00:00Z"),e=structuredClone(t);expect(e.getTime()).toEqual(t.getTime())}),it("Clones a Buffer",()=>{let t=Buffer.from("hello world"),e=structuredClone(t);expect(e.buffer).toEqual(t.buffer),t.set([1,2,3,4,5,6,7,8]),expect(e).not.toStrictEqual(t)}),it("Handles transfer list",()=>{let t={foo:{bar:"baz",arr:[1,2,3]}},e=structuredClone(t);expect(e.foo.arr).not.toBe(t.foo.arr);let o=structuredClone(t,{transfer:[t.foo.arr]});expect(o.foo.arr).toEqual(t.foo.arr)})});
